32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PROCESSING_FEE = 5;
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	
49	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
54	
55	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
56	
57	const DEDUCTIBLE = 100;
58	const PAYOUT_CAP_MULTIPLIER = 2;
59	
60	const HIGH_ENCHANTMENT_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
62	
63	const INSURANCE_VALUES: Record<string, number> = {
64	  sword: 1000,
65	  amulet: 600,
66	  staff: 800,
67	  potion: 400,
68	  rune: 250,
69	  moonstone: 250,
70	};
71	
72	const countItemsByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const basePremiumForGroup = (type: string, count: number): number =>
81	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
82	
83	const calculateTotalBasePremium = (items: Item[]): number =>
84	  [...countItemsByType(items)].reduce(
85	    (total, [type, count]) => total + basePremiumForGroup(type, count),
86	    0,
87	  );
88	
89	const curseSurchargeForItem = (item: Item): number =>
90	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
91	
92	const enchantmentSurchargeForItem = (item: Item): number =>
93	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
94	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
95	    : 0;
96	
97	const sumSurcharges = (
98	  items: Item[],
99	  surchargeForItem: (item: Item) => number,
100	): number =>
101	  items.reduce((total, item) => total + surchargeForItem(item), 0);
102	
103	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
104	  const loyaltyDiscountRate =
105	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
106	      ? LOYALTY_DISCOUNT_RATE
107	      : 0;
108	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
109	  return loyaltyDiscountRate + followUpDiscountRate;
110	};
111	
112	const payoutCapForItems = (items: Item[]): number =>
113	  PAYOUT_CAP_MULTIPLIER *
114	  items.reduce((total, item) => total + INSURANCE_VALUES[item.type], 0);
115	
116	const reimbursementForDamage = (
117	  damage: Damage,
118	  policyItems: Item[],
119	): number => {
120	  const damagedItem = policyItems.find(
121	    (item) => item.type === damage.itemType,
122	  );
123	  return (damagedItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
124	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
125	    : damage.amount;
126	};
127	
128	const claimStep = (step: ClaimStep, steps: Step[]): ClaimResult => {
129	  const policyItems = (steps[step.policy] as QuoteStep).items;
130	  const payoutCap = payoutCapForItems(policyItems);
131	  const damage = step.incident.damages[0];
132	  const payout = reimbursementForDamage(damage, policyItems) - DEDUCTIBLE;
133	  return {
134	    payout,
135	    remainingCap: payoutCap - payout,
136	  };
137	};
138	
139	const quoteStep = (
140	  step: QuoteStep,
141	  customer: Customer,
142	  stepIndex: number,
143	): QuoteResult => {
144	  const totalBasePremium = calculateTotalBasePremium(step.items);
145	  const firstInsuranceSurcharge =
146	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
147	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
148	  const enchantmentSurcharge = sumSurcharges(
149	    step.items,
150	    enchantmentSurchargeForItem,
151	  );
152	  const discount =
153	    totalBasePremium * policyDiscountRate(customer, stepIndex);
154	  return {
155	    premium: Math.ceil(
156	      totalBasePremium + firstInsuranceSurcharge + curseSurcharge +
157	        enchantmentSurcharge - discount + PROCESSING_FEE,
158	    ),
159	  };
160	};
161	
162	export const processScenario = (scenario: Scenario): ScenarioResult => ({
163	  results: scenario.steps.map((step, index) =>
164	    "incident" in step
165	      ? claimStep(step, scenario.steps)
166	      : quoteStep(step, scenario.customer, index),
167	  ),
168	});
